diff --git a/org.eclipse.wildwebdeveloper/src/org/eclipse/wildwebdeveloper/SchemaAssociation.java b/org.eclipse.wildwebdeveloper/src/org/eclipse/wildwebdeveloper/SchemaAssociation.java
